import threading, sys, time
sys.path.insert(0, 'src')
from assay_engine import provenance as P

# Force a realistic yield between the read (seq/prev_hash) and the append by using a slow clock.
# This models the real compute window (clock/digest/freeze) where the GIL CAN be released.
def slow_clock():
    import datetime as dt
    time.sleep(0.0001)  # GIL yield point inside the read-compute-append window
    return dt.datetime.now(tz=dt.timezone.utc)

def run(locked):
    trail = P.ProvenanceTrail(clock=slow_clock)
    barrier = threading.Barrier(8)
    def worker(w):
        barrier.wait()
        for i in range(20):
            if locked:
                trail.record('k', f'w{w}-{i}', w=w, i=i)
            else:
                trail._record_locked('k', f'w{w}-{i}', {'w': w, 'i': i})
    threads = [threading.Thread(target=worker, args=(w,)) for w in range(8)]
    for th in threads: th.start()
    for th in threads: th.join()
    seqs = sorted(e.seq for e in trail.entries)
    ok = (len(trail)==160 and seqs==list(range(160)))
    try:
        trail.verify(); v=True
    except Exception: v=False
    return ok, v

print('UNLOCKED (pre-fix):', run(False))
print('LOCKED   (fix)    :', run(True))
